export const MANUAL_HTML = "<title>School Leader's Manual — MAESTRO-SMS</title>\n\n<style>\n  /* ---- Tokens: derived from the product's own brand (navy + logo green) ---- */\n  :root {\n    --ink: #0E2438;\n    --brand: #16496E;\n    --brand-lift: #2A6FA0;\n    --affirm: #46812F;\n    --caution: #8F5D0C;\n    --paper: #F6F9FB;\n    --card: #FFFFFF;\n    --rule: #DAE3EA;\n    --rule-soft: #EAF0F5;\n    --muted: #566A78;\n    --shadow: 0 1px 2px rgba(14, 36, 56, .06), 0 8px 24px rgba(14, 36, 56, .05);\n\n    --serif: Georgia, \"Iowan Old Style\", \"Times New Roman\", serif;\n    --sans: ui-sans-serif, system-ui, -apple-system, \"Segoe UI\", Roboto, Helvetica, Arial, sans-serif;\n    --mono: ui-monospace, SFMono-Regular, \"SF Mono\", Menlo, Consolas, monospace;\n\n    --step-0: 1rem;\n    --step-1: 1.15rem;\n    --step-2: 1.4rem;\n    --step-3: 1.85rem;\n    --step-4: 2.6rem;\n  }\n\n  @media (prefers-color-scheme: dark) {\n    :root {\n      --ink: #E2ECF3;\n      --brand: #6BB0DD;\n      --brand-lift: #8FC7EC;\n      --affirm: #86C468;\n      --caution: #D3A257;\n      --paper: #0B1620;\n      --card: #12212C;\n      --rule: #24394A;\n      --rule-soft: #1A2C3A;\n      --muted: #94A9B9;\n      --shadow: 0 1px 2px rgba(0, 0, 0, .3), 0 8px 24px rgba(0, 0, 0, .25);\n    }\n  }\n\n  :root[data-theme=\"dark\"] {\n    --ink: #E2ECF3;\n    --brand: #6BB0DD;\n    --brand-lift: #8FC7EC;\n    --affirm: #86C468;\n    --caution: #D3A257;\n    --paper: #0B1620;\n    --card: #12212C;\n    --rule: #24394A;\n    --rule-soft: #1A2C3A;\n    --muted: #94A9B9;\n    --shadow: 0 1px 2px rgba(0, 0, 0, .3), 0 8px 24px rgba(0, 0, 0, .25);\n  }\n\n  :root[data-theme=\"light\"] {\n    --ink: #0E2438;\n    --brand: #16496E;\n    --brand-lift: #2A6FA0;\n    --affirm: #46812F;\n    --caution: #8F5D0C;\n    --paper: #F6F9FB;\n    --card: #FFFFFF;\n    --rule: #DAE3EA;\n    --rule-soft: #EAF0F5;\n    --muted: #566A78;\n    --shadow: 0 1px 2px rgba(14, 36, 56, .06), 0 8px 24px rgba(14, 36, 56, .05);\n  }\n\n  * { box-sizing: border-box; }\n\n  body {\n    margin: 0;\n    background: var(--paper);\n    color: var(--ink);\n    font-family: var(--sans);\n    font-size: var(--step-0);\n    line-height: 1.62;\n    -webkit-font-smoothing: antialiased;\n  }\n\n  /* ---- Masthead ---- */\n  .masthead {\n    background: var(--brand);\n    color: #fff;\n    padding: 3.2rem 1.5rem 2.6rem;\n    border-bottom: 3px solid var(--affirm);\n  }\n  :root[data-theme=\"dark\"] .masthead,\n  .masthead { background: linear-gradient(160deg, #16496E 0%, #0F3550 100%); }\n\n  .masthead-inner { max-width: 1160px; margin: 0 auto; display: flex; flex-direction: column; gap: .9rem; }\n  .eyebrow {\n    font-family: var(--mono);\n    font-size: .72rem;\n    letter-spacing: .16em;\n    text-transform: uppercase;\n    color: #A8D4EE;\n  }\n  .masthead h1 {\n    font-family: var(--serif);\n    font-size: var(--step-4);\n    line-height: 1.1;\n    margin: 0;\n    font-weight: 600;\n    text-wrap: balance;\n    color: #fff;\n  }\n  .masthead p { margin: 0; max-width: 62ch; color: #CFE4F2; font-size: var(--step-1); }\n  .masthead-meta {\n    display: flex; flex-wrap: wrap; gap: 1.4rem;\n    margin-top: .6rem; padding-top: 1.2rem;\n    border-top: 1px solid rgba(255, 255, 255, .18);\n    font-family: var(--mono); font-size: .74rem; letter-spacing: .06em; color: #A8D4EE;\n  }\n\n  /* ---- Shell ---- */\n  .shell {\n    max-width: 1160px;\n    margin: 0 auto;\n    padding: 0 1.5rem 5rem;\n    display: grid;\n    grid-template-columns: 244px minmax(0, 1fr);\n    gap: 3.2rem;\n    align-items: start;\n  }\n\n  /* ---- Contents rail ---- */\n  .rail { position: sticky; top: 1.5rem; padding-top: 2.4rem; max-height: calc(100vh - 3rem); overflow-y: auto; }\n  .rail h2 {\n    font-family: var(--mono); font-size: .7rem; letter-spacing: .16em;\n    text-transform: uppercase; color: var(--muted); margin: 0 0 .9rem;\n  }\n  .rail ol { list-style: none; margin: 0; padding: 0; display: flex; flex-direction: column; gap: .1rem; }\n  .rail a {\n    display: block; padding: .34rem .6rem .34rem .75rem;\n    color: var(--muted); text-decoration: none; font-size: .855rem;\n    border-left: 2px solid var(--rule); line-height: 1.4;\n  }\n  .rail a:hover { color: var(--brand); border-left-color: var(--brand-lift); background: var(--rule-soft); }\n  .rail a.active { color: var(--brand); border-left-color: var(--brand); font-weight: 600; background: var(--rule-soft); }\n\n  .toc-toggle { display: none; }\n\n  /* ---- Content ---- */\n  main { padding-top: 2.4rem; min-width: 0; }\n  section { scroll-margin-top: 1.5rem; margin-bottom: 3.4rem; }\n\n  .sec-label {\n    font-family: var(--mono); font-size: .7rem; letter-spacing: .16em;\n    text-transform: uppercase; color: var(--brand-lift); margin-bottom: .5rem;\n  }\n  h2.sec-title {\n    font-family: var(--serif); font-size: var(--step-3); line-height: 1.2;\n    margin: 0 0 1rem; font-weight: 600; text-wrap: balance;\n    padding-bottom: .7rem; border-bottom: 1px solid var(--rule);\n  }\n  h3 {\n    font-family: var(--serif); font-size: var(--step-2); line-height: 1.25;\n    margin: 2.2rem 0 .7rem; font-weight: 600; text-wrap: balance;\n  }\n  h4 {\n    font-size: .96rem; margin: 1.5rem 0 .45rem; font-weight: 700;\n    letter-spacing: .01em; color: var(--ink);\n  }\n  p, li { max-width: 68ch; }\n  p { margin: 0 0 1rem; }\n  ul, ol.body-list { margin: 0 0 1.15rem; padding-left: 1.3rem; }\n  li { margin-bottom: .42rem; }\n  a { color: var(--brand); }\n  strong { font-weight: 650; }\n  code {\n    font-family: var(--mono); font-size: .84em;\n    background: var(--rule-soft); padding: .1em .38em;\n    border-radius: 3px; border: 1px solid var(--rule);\n  }\n  .lede { font-size: var(--step-1); color: var(--muted); max-width: 66ch; }\n\n  /* ---- Callouts: each encodes a real, recurring rule in this system ---- */\n  .note {\n    border-left: 3px solid var(--brand);\n    background: var(--card);\n    padding: 1rem 1.2rem;\n    margin: 1.3rem 0;\n    box-shadow: var(--shadow);\n    border-radius: 0 5px 5px 0;\n  }\n  .note.two-person { border-left-color: var(--caution); }\n  .note.safe { border-left-color: var(--affirm); }\n  .note p:last-child { margin-bottom: 0; }\n  .note-tag {\n    display: block; font-family: var(--mono); font-size: .68rem;\n    letter-spacing: .14em; text-transform: uppercase;\n    color: var(--brand); margin-bottom: .4rem;\n  }\n  .note.two-person .note-tag { color: var(--caution); }\n  .note.safe .note-tag { color: var(--affirm); }\n\n  /* ---- Step sequence (only used where order is genuinely load-bearing) ---- */\n  .steps { list-style: none; margin: 1.4rem 0; padding: 0; display: flex; flex-direction: column; gap: 0; counter-reset: step; }\n  .steps > li {\n    counter-increment: step;\n    position: relative;\n    padding: 0 0 1.5rem 3.1rem;\n    border-left: 1px solid var(--rule);\n    margin-left: .95rem;\n    max-width: none;\n  }\n  .steps > li:last-child { border-left-color: transparent; padding-bottom: 0; }\n  .steps > li::before {\n    content: counter(step);\n    position: absolute; left: -.95rem; top: -.1rem;\n    width: 1.9rem; height: 1.9rem; border-radius: 50%;\n    background: var(--card); border: 1px solid var(--rule);\n    color: var(--brand); font-family: var(--mono); font-size: .78rem; font-weight: 600;\n    display: grid; place-items: center;\n  }\n  .steps h4 { margin: 0 0 .3rem; }\n  .steps p { margin-bottom: .5rem; }\n  .where {\n    font-family: var(--mono); font-size: .75rem; color: var(--muted);\n    display: block; margin-bottom: .45rem;\n  }\n\n  /* ---- Tables ---- */\n  .table-wrap { overflow-x: auto; margin: 1.3rem 0; border: 1px solid var(--rule); border-radius: 6px; background: var(--card); }\n  table { border-collapse: collapse; width: 100%; font-size: .89rem; min-width: 480px; }\n  th, td { text-align: left; padding: .68rem .9rem; border-bottom: 1px solid var(--rule-soft); vertical-align: top; }\n  th {\n    font-family: var(--mono); font-size: .7rem; letter-spacing: .1em;\n    text-transform: uppercase; color: var(--muted);\n    background: var(--rule-soft); border-bottom: 1px solid var(--rule);\n    white-space: nowrap;\n  }\n  tr:last-child td { border-bottom: none; }\n  td.num { font-variant-numeric: tabular-nums; white-space: nowrap; }\n  td code { background: transparent; border: none; padding: 0; color: var(--brand); }\n\n  /* ---- Rhythm cards ---- */\n  .cards { display: grid; grid-template-columns: repeat(auto-fit, minmax(230px, 1fr)); gap: 1rem; margin: 1.4rem 0; }\n  .card {\n    background: var(--card); border: 1px solid var(--rule);\n    border-radius: 6px; padding: 1.1rem 1.2rem; box-shadow: var(--shadow);\n  }\n  .card h4 { margin: 0 0 .55rem; font-family: var(--mono); font-size: .72rem; letter-spacing: .13em; text-transform: uppercase; color: var(--brand); }\n  .card ul { margin: 0; padding-left: 1.1rem; font-size: .89rem; }\n  .card li { margin-bottom: .35rem; max-width: none; }\n\n  /* ---- FAQ ---- */\n  details {\n    border-bottom: 1px solid var(--rule); padding: .85rem 0;\n  }\n  summary {\n    cursor: pointer; font-weight: 600; list-style: none;\n    display: flex; gap: .7rem; align-items: baseline;\n  }\n  summary::-webkit-details-marker { display: none; }\n  summary::before { content: \"+\"; font-family: var(--mono); color: var(--brand); font-weight: 700; }\n  details[open] summary::before { content: \"\\2212\"; }\n  details p { margin: .7rem 0 0 1.4rem; }\n  details:focus-within summary { outline: 2px solid var(--brand); outline-offset: 3px; border-radius: 3px; }\n\n  a:focus-visible, summary:focus-visible { outline: 2px solid var(--brand); outline-offset: 3px; border-radius: 3px; }\n\n  footer.doc-foot {\n    border-top: 1px solid var(--rule); margin-top: 1rem; padding-top: 1.4rem;\n    font-size: .85rem; color: var(--muted);\n  }\n\n  @media (max-width: 900px) {\n    .shell { grid-template-columns: minmax(0, 1fr); gap: 0; }\n    .rail {\n      position: static; max-height: none; padding-top: 1.6rem;\n      border-bottom: 1px solid var(--rule); padding-bottom: 1rem; margin-bottom: 1rem;\n    }\n    .toc-toggle {\n      display: block; width: 100%; text-align: left; cursor: pointer;\n      background: var(--card); border: 1px solid var(--rule); border-radius: 5px;\n      padding: .7rem .9rem; font-family: var(--mono); font-size: .74rem;\n      letter-spacing: .13em; text-transform: uppercase; color: var(--brand);\n    }\n    .rail h2 { display: none; }\n    .rail ol[hidden] { display: none; }\n    .rail ol { margin-top: .8rem; }\n    main { padding-top: 0; }\n    .masthead h1 { font-size: 2rem; }\n  }\n\n  @media print {\n    .rail, .toc-toggle { display: none; }\n    .shell { display: block; max-width: none; padding: 0; }\n    .masthead { background: none; color: #000; border-bottom: 2px solid #000; padding: 0 0 1rem; }\n    .masthead h1, .masthead p, .eyebrow, .masthead-meta { color: #000; }\n    section { page-break-inside: avoid; }\n    details { page-break-inside: avoid; }\n    details > * { display: block !important; }\n  }\n\n  @media (prefers-reduced-motion: reduce) {\n    * { animation: none !important; transition: none !important; scroll-behavior: auto !important; }\n  }\n</style>\n\n<header class=\"masthead\">\n  <div class=\"masthead-inner\">\n    <div class=\"eyebrow\">Onboarding Manual</div>\n    <h1>Running your school on MAESTRO-SMS</h1>\n    <p>A complete working guide for proprietors and principals — from first login to a school that runs itself.</p>\n    <div class=\"masthead-meta\">\n      <span>For: Owners &amp; Principals</span>\n      <span>Read once, then keep as reference</span>\n      <span>Live help inside the app: <strong>Help</strong></span>\n    </div>\n  </div>\n</header>\n\n<div class=\"shell\">\n  <nav class=\"rail\" aria-label=\"Contents\">\n    <button class=\"toc-toggle\" id=\"tocToggle\" aria-expanded=\"false\" aria-controls=\"tocList\">Contents</button>\n    <h2>Contents</h2>\n    <ol id=\"tocList\">\n      <li><a href=\"#start\">Start here</a></li>\n      <li><a href=\"#roles-you\">Owner vs. Principal</a></li>\n      <li><a href=\"#first-login\">Your first login</a></li>\n      <li><a href=\"#launch\">The first 30 days</a></li>\n      <li><a href=\"#navigating\">Finding your way around</a></li>\n      <li><a href=\"#delegation\">Delegating: the role model</a></li>\n      <li><a href=\"#rails\">The safety rails</a></li>\n      <li><a href=\"#fees\">Money in: school fees</a></li>\n      <li><a href=\"#subscription\">Money out: your subscription</a></li>\n      <li><a href=\"#academic\">The academic core</a></li>\n      <li><a href=\"#people\">Staff, parents &amp; communication</a></li>\n      <li><a href=\"#rhythm\">Your operating rhythm</a></li>\n      <li><a href=\"#troubleshooting\">When something goes wrong</a></li>\n      <li><a href=\"#reference\">Quick reference</a></li>\n    </ol>\n  </nav>\n\n  <main>\n\n    <!-- ================================================================= -->\n    <section id=\"start\">\n      <div class=\"sec-label\">Orientation</div>\n      <h2 class=\"sec-title\">Start here</h2>\n      <p class=\"lede\">This manual assumes you have never used the system before, and that you are accountable for it — not merely a user of it.</p>\n\n      <p>MAESTRO-SMS is the single place your school's records live: students and their families, classes and timetables, attendance, grades and report cards, fees and payments, staff employment and payroll, and the approvals that govern all of it. Everything is tied to one school — yours. Staff at another school on the same platform cannot see your data, and you cannot see theirs. That separation is enforced in three independent layers of the system, not by a setting anyone can toggle.</p>\n\n      <p>Two ideas explain most of how the system behaves, and if you take nothing else from this manual, take these:</p>\n\n      <p><strong>You see only what your role permits.</strong> The menu down the left-hand side is not the same for you as it is for a teacher or a parent. Items are not greyed out — they are simply absent. So when a member of staff tells you \"I can't find it,\" the usual answer is that they don't have that role, not that the system is broken.</p>\n\n      <p><strong>Anything that moves money or grants power needs two people.</strong> A large payment, a refund, a salary change, a published grade, appointing a junior administrator — one person requests, a different person approves. This is deliberate. It protects your staff as much as it protects you, because it means no single person can ever be solely blamed for a disputed transaction.</p>\n\n      <div class=\"note\">\n        <span class=\"note-tag\">Where to get help</span>\n        <p>The app has a built-in <strong>Help</strong> page that adapts to whoever is signed in — a teacher sees teacher guidance, an accountant sees finance guidance. Send staff there first. This manual is the leadership view that sits above it.</p>\n      </div>\n    </section>\n\n    <!-- ================================================================= -->\n    <section id=\"roles-you\">\n      <div class=\"sec-label\">Your position</div>\n      <h2 class=\"sec-title\">Owner vs. Principal — who controls what</h2>\n\n      <p>The system does not have a role literally called \"owner\". Proprietors are normally set up as <strong>school administrator</strong>, and heads of school as <strong>principal</strong>. The two overlap heavily but are deliberately not identical, and understanding the split saves a great deal of confusion later.</p>\n\n      <div class=\"table-wrap\">\n        <table>\n          <thead>\n            <tr><th>Responsibility</th><th>School administrator</th><th>Principal</th></tr>\n          </thead>\n          <tbody>\n            <tr><td>Configuration — settings, branding, integrations</td><td>Yes</td><td>No</td></tr>\n            <tr><td>Managing roles and staff access</td><td>Yes</td><td>No</td></tr>\n            <tr><td>Subscription, plan and billing</td><td>Yes</td><td>Yes</td></tr>\n            <tr><td>Approving fees, refunds and salary changes</td><td>Yes</td><td>Yes</td></tr>\n            <tr><td>Final stage of the staff approval chain</td><td>No</td><td>Yes</td></tr>\n            <tr><td>Academic oversight — grades, publishing results</td><td>Yes</td><td>Yes</td></tr>\n            <tr><td>Releasing exam answers after a test</td><td>No</td><td>Yes</td></tr>\n          </tbody>\n        </table>\n      </div>\n\n      <p>The rule behind the split: the <strong>administrator configures</strong> the system, the <strong>principal operates</strong> the school. A principal should not be able to quietly change a setting that weakens a control they are also the final approver for.</p>\n\n      <div class=\"note two-person\">\n        <span class=\"note-tag\">Deliberate design</span>\n        <p>If you are both proprietor and head of school, ask to hold both roles — this is normal and supported. But do not hold both <em>and</em> expect to approve your own requests. The system will refuse: every approval stage must be decided by a different person from the one who raised it. Where a school genuinely has only one senior person, appoint a second trusted approver before you need one, not during the emergency.</p>\n      </div>\n\n      <h3>Two roles you will never see</h3>\n      <p>There are two platform-level roles — <strong>super administrator</strong> and <strong>manager administrator</strong> — that belong to MajorGBN, not to your school. They are invisible in your role list and cannot be created or assigned by anyone at your school, including you. They exist so the platform team can support you; every action they take in your school is written to an audit log you can read.</p>\n    </section>\n\n    <!-- ================================================================= -->\n    <section id=\"first-login\">\n      <div class=\"sec-label\">Day one</div>\n      <h2 class=\"sec-title\">Your first login, and keeping the account safe</h2>\n\n      <p>When your school is provisioned you receive a sign-in email containing a <strong>set-password link, not a password</strong>. The link is single-use and expires after seven days. If it lapses, use <em>Forgot password</em> on the login page rather than asking for the link again.</p>\n\n      <h3>Set up two-factor authentication immediately</h3>\n      <p>Go to <strong>Account</strong> and enrol an authenticator app. Your account is the most valuable one in your school — it can move money and grant access. Do this before you invite anyone else, so you can honestly ask them to do the same.</p>\n\n      <p>Once your own is working, consider turning on <strong>Admin → Roles → Require two-factor authentication for staff</strong>. It applies to every staff member and none of your students or parents. Staff who have not enrolled are held on their Account page until they do — they are not locked out, so it will not strand anyone mid-lesson.</p>\n\n      <h3>What the system does to protect you automatically</h3>\n\n      <div class=\"table-wrap\">\n        <table>\n          <thead><tr><th>Protection</th><th>Behaviour</th></tr></thead>\n          <tbody>\n            <tr><td>Idle sign-out</td><td>After 10 minutes of inactivity you are signed out. A warning dialog with a 60-second countdown appears first, and you can extend from there. You return to the exact page you left.</td></tr>\n            <tr><td>Failed logins</td><td class=\"num\">3 wrong passwords locks the account permanently until an administrator reactivates it.</td></tr>\n            <tr><td>Password age</td><td class=\"num\">Passwords must be changed every 30 days.</td></tr>\n            <tr><td>Re-authentication</td><td>Especially sensitive actions ask for your password again, even though you are already signed in. Entry is masked.</td></tr>\n          </tbody>\n        </table>\n      </div>\n\n      <div class=\"note two-person\">\n        <span class=\"note-tag\">Plan for this before it happens</span>\n        <p>Three wrong passwords locks an account and only an administrator can reactivate it. If your school has exactly one administrator and that account locks, you must <a href=\"#contact\">contact us</a> to recover — WhatsApp is fastest for this. <strong>Appoint a second administrator on day one.</strong> It costs nothing and removes the single most common way schools lock themselves out.</p>\n      </div>\n    </section>\n\n    <!-- ================================================================= -->\n    <section id=\"launch\">\n      <div class=\"sec-label\">Implementation</div>\n      <h2 class=\"sec-title\">The first 30 days</h2>\n      <p class=\"lede\">This order is not arbitrary. Each step depends on the one before it — students cannot be enrolled into classes that don't exist, and fees cannot be invoiced to students who haven't been imported.</p>\n\n      <h3>Week 1 — People and structure</h3>\n      <ol class=\"steps\">\n        <li>\n          <h4>Create your staff accounts</h4>\n          <span class=\"where\">Admin → Users, then Admin → Roles</span>\n          <p>Add teachers, your accountant, HR staff and your second administrator. Each receives a one-time temporary password and must set their own at first login. Assign roles as you go — a member of staff with no role can sign in but will see almost nothing.</p>\n        </li>\n        <li>\n          <h4>Import your students</h4>\n          <span class=\"where\">Admin → Bulk import</span>\n          <p>Upload a CSV. The import is safe to re-run — it matches on email address, so a repeated upload updates rather than duplicates. Parent links can be imported in the same pass, which saves considerable work later. On approval the system generates printable login slips with a unique one-time password per student.</p>\n        </li>\n        <li>\n          <h4>Build classes, subjects and the academic session</h4>\n          <span class=\"where\">Classes</span>\n          <p>Create each class, assign its teachers, and name a <strong>class supervisor</strong> (form teacher) — that person writes the class remark on report cards, so don't skip it. Enrol students, link guardians, then set up your session and its terms. Grading has nowhere to record marks until terms exist.</p>\n        </li>\n      </ol>\n\n      <h3>Week 2 — Timetable and fees</h3>\n      <ol class=\"steps\">\n        <li>\n          <h4>Define periods and rooms, then place lessons</h4>\n          <span class=\"where\">Timetable</span>\n          <p>Double-bookings are rejected as you go — the same teacher, room or class cannot be scheduled twice in one period. If you would rather not build the grid by hand, set how many lessons per week each subject needs and use <strong>Generate</strong>: the system solves the timetable for you and tells you precisely which lessons it could not place and why.</p>\n        </li>\n        <li>\n          <h4>Build your fee catalogue and issue invoices</h4>\n          <span class=\"where\">Fees</span>\n          <p>Create your fee items, then issue invoices. Register the bank account fees should settle into. Parents can pay online by card immediately; the money reaches your account, not MajorGBN's.</p>\n        </li>\n      </ol>\n\n      <h3>Week 3 — Public face and examinations</h3>\n      <ol class=\"steps\">\n        <li>\n          <h4>Brand your portal</h4>\n          <span class=\"where\">Admin → Branding</span>\n          <p>Upload your logo (square, between 128 and 2048 pixels) and set your school colour and font. It appears for every member of your school and on generated documents — report cards, receipts, certificates and ID cards.</p>\n        </li>\n        <li>\n          <h4>Review incoming admissions</h4>\n          <span class=\"where\">Admin → Admissions</span>\n          <p>Applications from your public application page arrive quarantined — an applicant is not a student and can see nothing until you admit them. If you charge an application fee, paid and unpaid status shows on each application.</p>\n        </li>\n        <li>\n          <h4>Schedule examinations</h4>\n          <span class=\"where\">Exams</span>\n          <p>Create a sitting with hall, date, time and capacity; seat an entire class in one action; roster invigilators. Students and parents then see their own hall, time and seat number, and invigilators see their duties — which removes an enormous amount of exam-week correspondence.</p>\n        </li>\n      </ol>\n\n      <h3>Week 4 — Governance and delegation</h3>\n      <ol class=\"steps\">\n        <li>\n          <h4>Walk the guardrails once, deliberately</h4>\n          <span class=\"where\">Admin → Audit, Security, Recertification, Privacy</span>\n          <p>Open each of the four. You do not need to act on anything — you need to know they exist and what each is for before the day you urgently need one. They are described in full under <a href=\"#rails\">The safety rails</a>.</p>\n        </li>\n        <li>\n          <h4>Appoint a junior administrator</h4>\n          <span class=\"where\">Admin → Roles</span>\n          <p>This is the single highest-value delegation available to you. A junior administrator handles day-to-day operations — records, attendance, timetable, recording fee payments, reviewing admissions — while every approval power stays with you. See <a href=\"#delegation\">Delegating</a>.</p>\n        </li>\n        <li>\n          <h4>Confirm your subscription</h4>\n          <span class=\"where\">Billing</span>\n          <p>Check your plan, your student count and your renewal date before your trial ends. Details under <a href=\"#subscription\">Money out</a>.</p>\n        </li>\n      </ol>\n    </section>\n\n    <!-- ================================================================= -->\n    <section id=\"navigating\">\n      <div class=\"sec-label\">Interface</div>\n      <h2 class=\"sec-title\">Finding your way around</h2>\n\n      <p>The left-hand menu is long because the system is broad. It helps to stop reading it as a list and start reading it as five groups.</p>\n\n      <div class=\"cards\">\n        <div class=\"card\">\n          <h4>Run the school</h4>\n          <ul>\n            <li>Dashboard, Analytics, Reports</li>\n            <li>Students, Classes, Timetable</li>\n            <li>Attendance, Grades</li>\n            <li>Exams, CBT exams, Assessments</li>\n          </ul>\n        </div>\n        <div class=\"card\">\n          <h4>Money</h4>\n          <ul>\n            <li>Fees — invoices, payments, disputes</li>\n            <li>Billing — your own subscription</li>\n          </ul>\n        </div>\n        <div class=\"card\">\n          <h4>People</h4>\n          <ul>\n            <li>HR — employment, payroll</li>\n            <li>Leave — including your own</li>\n            <li>Meetings, Messages, Announcements</li>\n          </ul>\n        </div>\n        <div class=\"card\">\n          <h4>Govern</h4>\n          <ul>\n            <li>Approvals — your decision queue</li>\n            <li>Admin — users, roles, audit, security</li>\n            <li>Documents, Certificates</li>\n          </ul>\n        </div>\n        <div class=\"card\">\n          <h4>Facilities &amp; extras</h4>\n          <ul>\n            <li>Hostel, Transport, Library</li>\n            <li>Tasks, Polls, Discussion, Forms</li>\n            <li>Discipline, Alumni, Games</li>\n          </ul>\n        </div>\n      </div>\n\n      <h3>Two shortcuts worth learning on day one</h3>\n      <p><strong>The search box in the header</strong> jumps straight to a student, staff member, class or invoice without navigating to the module first. For a principal answering a parent on the phone, this is the fastest route to an answer that exists in the system.</p>\n      <p><strong>Approvals</strong> is your queue. If you check one page each morning, make it this one — it is where everything waiting on <em>your</em> decision collects, and where work quietly stalls if you don't.</p>\n\n      <h3>Why a colleague's menu looks different</h3>\n      <p>Two independent things decide whether a menu item appears:</p>\n      <ul>\n        <li><strong>Your role</strong> — whether you personally are permitted to use that area.</li>\n        <li><strong>Your school's plan</strong> — whether your subscription includes that module at all.</li>\n      </ul>\n      <p>If an entire area is missing for everyone including you, it is the plan. If it is missing for one person only, it is their role. That single distinction resolves most \"it's not there\" questions without a support call.</p>\n    </section>\n\n    <!-- ================================================================= -->\n    <section id=\"delegation\">\n      <div class=\"sec-label\">Leadership</div>\n      <h2 class=\"sec-title\">Delegating: the role model</h2>\n\n      <p class=\"lede\">There are 17 school-level roles. You will not use all of them. The goal is to give each person exactly what their job requires and nothing more — which protects them from being blamed for things they could not have done.</p>\n\n      <h3>The roles you will actually assign</h3>\n      <div class=\"table-wrap\">\n        <table>\n          <thead><tr><th>Role</th><th>Appoint when you need someone to…</th></tr></thead>\n          <tbody>\n            <tr><td><strong>School administrator</strong></td><td>Configure the system and manage staff access. Appoint at least two.</td></tr>\n            <tr><td><strong>Principal</strong></td><td>Run the school and sit as final approver on staff requests.</td></tr>\n            <tr><td><strong>Junior administrator</strong></td><td>Do the daily administrative work without holding any approval power.</td></tr>\n            <tr><td><strong>Teacher</strong></td><td>Teach, take the register and enter marks — for their own classes only.</td></tr>\n            <tr><td><strong>Head teacher</strong></td><td>Act as the first approval stage for staff requests.</td></tr>\n            <tr><td><strong>Head administrator</strong></td><td>Act as first approval stage on the administrative side.</td></tr>\n            <tr><td><strong>Accountant</strong></td><td>Manage fees, invoices and payments day to day.</td></tr>\n            <tr><td><strong>HR clerk</strong></td><td>Maintain staff records without seeing or setting pay.</td></tr>\n            <tr><td><strong>HR manager</strong></td><td>Own leave, salary and payroll, and approve at stage two.</td></tr>\n            <tr><td><strong>Board</strong></td><td>Oversee, read-only, with a veto on approvals. No operational access.</td></tr>\n            <tr><td><strong>Librarian</strong> · <strong>Warden</strong> · <strong>Driver</strong></td><td>Run the library, a hostel, or drive a vehicle — each scoped to their own.</td></tr>\n            <tr><td><strong>Head warden</strong> · <strong>Head driver</strong></td><td>Oversee every hostel, or the whole fleet.</td></tr>\n          </tbody>\n        </table>\n      </div>\n\n      <h3>The junior administrator, specifically</h3>\n      <p>This role deserves separate attention because it is the one that will most reduce your daily workload. A junior administrator can maintain records, take and correct attendance, adjust the timetable, manage documents, <strong>record</strong> fee payments, and review admissions. They cannot manage roles, cannot approve fees, and cannot sit in any approval chain.</p>\n      <p>In other words: they can do the work, but they cannot authorise it. That is precisely the shape you want for a capable office administrator you do not yet want holding financial authority.</p>\n\n      <div class=\"note two-person\">\n        <span class=\"note-tag\">Requires a second approver</span>\n        <p>Appointing a junior administrator — or adding any further role to someone who already is one — raises an approval request that a <strong>different</strong> senior must confirm under <strong>Approvals</strong>. You cannot approve your own appointment. This is intentional: quietly promoting someone is the classic route to an internal fraud, and requiring a second signature closes it.</p>\n      </div>\n\n      <h3>Two protections on your own role</h3>\n      <ul>\n        <li><strong>You cannot remove your own</strong> administrator or principal role. This prevents an accidental self-lockout.</li>\n        <li><strong>The last senior role in a school cannot be removed.</strong> Your school can never end up with nobody in charge.</li>\n      </ul>\n\n      <h3>When someone leaves</h3>\n      <p>Revoke the account under <strong>Admin → Users</strong>. Access ends immediately — not at their next login. Any session they currently have open stops working on their very next action, and any unused invitation link they hold becomes invalid.</p>\n      <p>Do not delete staff records. Employment history, payroll entries and audit trails are statutory records, and the system deliberately retains them. Revoking access and retaining the record is the correct outcome, and it is what an auditor will expect to see.</p>\n    </section>\n\n    <!-- ================================================================= -->\n    <section id=\"rails\">\n      <div class=\"sec-label\">Governance</div>\n      <h2 class=\"sec-title\">The safety rails</h2>\n      <p class=\"lede\">These are the features that separate a school management system from a spreadsheet. Understand them once and you will trust the numbers the system gives you.</p>\n\n      <h3>Two people for anything that matters</h3>\n      <p>The system enforces separation of duties in code, not policy. The person who requests can never be the person who approves — even when they hold both roles.</p>\n\n      <div class=\"table-wrap\">\n        <table>\n          <thead><tr><th>Action</th><th>Raised by</th><th>Approved by</th></tr></thead>\n          <tbody>\n            <tr><td>Payment of ₦50,000 or more</td><td>Whoever records it</td><td>A different member of finance staff</td></tr>\n            <tr><td>Any refund, of any size</td><td>Whoever records it</td><td>A different member of finance staff</td></tr>\n            <tr><td>Fee discount or waiver</td><td>Whoever requests it</td><td>A different approver</td></tr>\n            <tr><td>Salary change</td><td>HR</td><td>Principal, administrator or HR manager</td></tr>\n            <tr><td>Payroll run finalisation</td><td>Whoever created the run</td><td>A different person</td></tr>\n            <tr><td>Appointing a junior administrator</td><td>An administrator</td><td>A different senior</td></tr>\n            <tr><td>Publishing grades</td><td>A teacher</td><td>Principal or administrator</td></tr>\n            <tr><td>Staff leave and requests</td><td>The member of staff</td><td>Head → HR manager → Principal</td></tr>\n          </tbody>\n        </table>\n      </div>\n\n      <p>Payments below ₦50,000 post immediately — small routine receipts are not held up. It is the large ones and every refund that wait, because those are the two shapes financial fraud actually takes.</p>\n\n      <h3>Audit — the record of who did what</h3>\n      <p><strong>Admin → Audit</strong> is a searchable log of every sensitive action taken in your school: who did it, to what, and when. Every reading of a student's medical record and every change to money or access is written here, and it cannot be edited or deleted by anyone — including MajorGBN.</p>\n      <p>Use it when a parent disputes a payment, when a mark appears to have changed, or when you simply want to know who altered something. It is also the fastest way to resolve an accusation between staff, because it replaces recollection with record.</p>\n\n      <h3>Temporary access, instead of permanent over-permissioning</h3>\n      <p>When someone needs access they do not normally hold — covering an absent colleague, say — <strong>Admin → Security</strong> grants it temporarily. It must be approved by a different person, it expires automatically, and every use of the elevated access is logged.</p>\n      <p>The alternative most schools reach for is granting a permanent role \"just for now\" and forgetting to remove it. Over a few years that is how everyone ends up with everything.</p>\n\n      <div class=\"note safe\">\n        <span class=\"note-tag\">A limit that also protects you</span>\n        <p>Temporary elevation can never grant platform-level or two-person-rule permissions. Nobody can use it to escalate themselves to approving their own refunds, managing roles, or reaching another school's data. The most sensitive permissions in the system are simply not obtainable this way.</p>\n      </div>\n\n      <h3>Access review</h3>\n      <p><strong>Admin → Recertification</strong> lists who currently holds what, and flags anything unusual. Work through it once a term. It takes twenty minutes and is the only reliable defence against permission creep.</p>\n\n      <h3>Data protection requests</h3>\n      <p><strong>Admin → Privacy</strong> handles the two rights families may exercise under NDPR: a full export of the data you hold on them, and a request for erasure. Erasure is reviewed rather than automatic, because some records — financial and statutory ones — you are legally required to keep. The system distinguishes the two for you.</p>\n    </section>\n\n    <!-- ================================================================= -->\n    <section id=\"fees\">\n      <div class=\"sec-label\">Finance</div>\n      <h2 class=\"sec-title\">Money in: school fees</h2>\n\n      <p>The flow is: build a <strong>catalogue</strong> of fee items, <strong>issue</strong> invoices from it, and let payments settle against them. An invoice moves through draft, issued, partially paid, and paid on its own as money arrives — you never set the status by hand.</p>\n\n      <h3>How parents pay</h3>\n      <ul>\n        <li><strong>Card, online</strong> — the parent pays from their own portal. Funds settle to <em>your</em> registered bank account.</li>\n        <li><strong>Bank transfer</strong> — each student can be issued a dedicated account number. A transfer into it is matched to the student and applied to their oldest open invoice automatically.</li>\n        <li><strong>Cash or in-person</strong> — recorded by your accountant, subject to the ₦50,000 two-person rule.</li>\n      </ul>\n      <p>Every posted payment sends a receipt to the payer, the guardians and the student, showing the remaining balance. Numbered PDF receipts can be downloaded at any time.</p>\n\n      <h3>Payment plans and credit</h3>\n      <p>An invoice can be split into instalments that must sum exactly to the total. The plan itself never moves money — each tranche simply reads as paid, due, overdue or upcoming based on what has actually been received.</p>\n      <p>Families can also pay in advance. Prepayments sit as a credit balance on the student and are applied to future invoices. Overpayments become credit automatically rather than needing a refund.</p>\n\n      <h3>Discounts, waivers and scholarships</h3>\n      <p>Discounts and waivers are requested and then approved by someone else, and the approved amount can never exceed what is actually outstanding. Separately, MajorGBN runs a <strong>platform-funded scholarship programme</strong> — a parent or teacher applies on a student's behalf, guardian consent is required, and an award is paid directly against that student's invoice at your school.</p>\n\n      <h3>Chargebacks and disputes</h3>\n      <p>If a parent disputes a card payment with their bank, it appears under <strong>Fees → Disputes</strong> with the deadline by which evidence must be submitted. Your finance staff are alerted automatically. Treat these as urgent: an unanswered dispute is normally lost by default, and a pattern of them puts your ability to accept card payments at risk.</p>\n\n      <h3>What to watch, and where</h3>\n      <p><strong>Fees → Reports</strong> gives you receivables ageing and collection rates. Overdue reminders go out weekly on their own, and late fees — if you configure them — are applied once per invoice, automatically. There is also a journal export for your accountant or auditor.</p>\n    </section>\n\n    <!-- ================================================================= -->\n    <section id=\"subscription\">\n      <div class=\"sec-label\">Commercial</div>\n      <h2 class=\"sec-title\">Money out: your subscription</h2>\n\n      <p>This is what your school pays MajorGBN, and it is entirely separate from the fees you collect from parents. It lives under <strong>Billing</strong>.</p>\n\n      <h3>How you are charged</h3>\n      <p>Pricing is <strong>per active student</strong>, multiplied by your plan's rate and the length of cycle you commit to. Committing further ahead costs less:</p>\n\n      <div class=\"table-wrap\">\n        <table>\n          <thead><tr><th>Cycle</th><th>Covers</th><th>Discount</th></tr></thead>\n          <tbody>\n            <tr><td>Monthly</td><td class=\"num\">1 month</td><td class=\"num\">—</td></tr>\n            <tr><td>Per term</td><td class=\"num\">3 months</td><td class=\"num\">5% off</td></tr>\n            <tr><td>Per year</td><td class=\"num\">9 months (three terms)</td><td class=\"num\">15% off</td></tr>\n          </tbody>\n        </table>\n      </div>\n\n      <p>Note that a \"year\" is the <strong>academic</strong> year — three terms, nine months — not twelve calendar months. It is priced to match how schools actually budget.</p>\n\n      <h3>Plans</h3>\n      <p>There are four tiers — <strong>Standard</strong>, <strong>Premium</strong>, <strong>Ultimate</strong> and <strong>Enterprise</strong> — each including everything in the tier below. Your plan decides which modules exist for your school at all; roles then decide who inside your school can use them. If you need a single module from a higher tier rather than the whole tier, ask <a href=\"#contact\">support</a> to enable it individually.</p>\n\n      <h3>Renewal, and what happens if you lapse</h3>\n      <p>A banner warns your billing staff from 14 days before renewal. You can save a card for automatic renewal, which is attempted about two days before expiry.</p>\n\n      <div class=\"note safe\">\n        <span class=\"note-tag\">Your data is never at risk</span>\n        <p>If a subscription lapses, access to <em>higher-tier modules</em> is suspended after a grace period — core teaching functions continue. Your data is never deleted, and paying restores full access immediately. A billing problem should never become an academic emergency, and it does not.</p>\n      </div>\n\n      <h3>Upgrading, and paying for growth</h3>\n      <p>Upgrade at any time — unused time on your current plan is credited against the new one, so you are not charged twice. If your student numbers grow mid-cycle, you are asked for a top-up covering the additional students for the remainder of the cycle only.</p>\n\n      <h3>Referrals</h3>\n      <p>Under <strong>Billing</strong> you can generate a referral code. When a school you refer takes their first paid subscription, <strong>both schools receive a free term</strong>. For a proprietor with peers running other schools, this is the cheapest way to reduce your own cost.</p>\n\n      <h3>If you run more than one school</h3>\n      <p>Proprietors with several campuses can add the <strong>Group console</strong>, which shows aggregate figures across all of them in one view. It deliberately shows numbers only — never student records — so a group-level view never becomes a route around each school's data separation.</p>\n    </section>\n\n    <!-- ================================================================= -->\n    <section id=\"academic\">\n      <div class=\"sec-label\">Operations</div>\n      <h2 class=\"sec-title\">The academic core</h2>\n\n      <h3>Attendance</h3>\n      <p>Teachers take a daily register per class. Marking a student absent or late notifies their guardians automatically — which is both a safeguarding measure and, in practice, the feature parents notice first.</p>\n\n      <h3>Grades and report cards</h3>\n      <p>Teachers enter marks for their own classes. Results are weighted per term, and <strong>publishing them requires approval</strong> — a teacher cannot release results to parents alone.</p>\n      <p>Report cards are generated as PDFs from actual grades and attendance, carry your branding, and include two written remarks: one from the class supervisor and one from the head. Each generated card is filed automatically into the student's document vault, so families can retrieve it later regardless of who produced it.</p>\n\n      <h3>Examinations</h3>\n      <p>Two separate things share the word \"exam\":</p>\n      <ul>\n        <li><strong>Exams</strong> — the logistics of physical examinations: halls, dates, seat allocation and invigilator rosters.</li>\n        <li><strong>CBT exams</strong> — computer-based tests sat in the system. The clock is enforced by the server, correct answers are withheld until a sitting closes, and answer release is gated to the principal. Automatic marks are presented as figures for staff to review, never as a final result.</li>\n      </ul>\n\n      <h3>Cover for absent teachers</h3>\n      <p>Under <strong>Timetable → Teacher cover</strong>, choose a date range and the system lists every lesson whose teacher is on approved leave. Assign a reliever and they are notified; the system refuses anyone already teaching in that period. This closes the gap where an approved leave request and an unattended class are tracked in two different places.</p>\n\n      <h3>Academic integrity</h3>\n      <p>For written assessments the system can detect signs of copying and contract cheating — pasted text, unusual typing patterns, similarity between submissions. Two things are worth stating plainly to your staff and your parents:</p>\n      <ul>\n        <li>It produces <strong>signals for a teacher to judge</strong>, never a verdict. No student is ever penalised automatically.</li>\n        <li>Monitoring is <strong>disclosed, consent-gated and time-limited</strong>, and individual students can be exempted where an accessibility need requires it.</li>\n      </ul>\n      <p>Being able to say this confidently to a concerned parent is part of why it is built this way.</p>\n    </section>\n\n    <!-- ================================================================= -->\n    <section id=\"people\">\n      <div class=\"sec-label\">Operations</div>\n      <h2 class=\"sec-title\">Staff, parents and communication</h2>\n\n      <h3>HR and payroll</h3>\n      <p><strong>HR</strong> holds employment records. Salaries are encrypted, and every read of them is logged — including the list view. Payroll runs snapshot each active employee's pay, calculate PAYE and pension, and must be finalised by someone other than whoever created the run. Payslips are available as PDFs, and there is a bank transfer export.</p>\n      <p>The module also covers recruitment, onboarding and offboarding checklists, document expiry reminders, appraisals, disciplinary case files, and final settlement when someone leaves.</p>\n\n      <h3>Leave</h3>\n      <p>Any member of staff applies under <strong>Leave</strong>. The request travels the approval chain, and on approval the balance is decremented automatically. Half-days are supported. Approved leave feeds directly into teacher cover.</p>\n\n      <h3>Parents</h3>\n      <p>A linked guardian sees their own children and nothing else: attendance, grades, invoices, documents, messages. This scoping is enforced by the system rather than by the interface, so a parent cannot reach another family's records by any route.</p>\n      <p><strong>Meetings</strong> lets staff open appointment slots that parents book themselves, for their own child only. It removes the scheduling correspondence around parents' evenings entirely.</p>\n\n      <h3>Reaching people</h3>\n      <ul>\n        <li><strong>Announcements</strong> — one-way, to a group.</li>\n        <li><strong>Messages</strong> — two-way conversations. Parents and students may only message staff, never each other.</li>\n        <li><strong>Notifications</strong> — automatic alerts: absence, invoices, receipts, approvals waiting on you.</li>\n      </ul>\n      <p>Email and in-app messages are unlimited. <strong>SMS and WhatsApp consume message credits</strong>, purchased in bundles under Billing. A credit is only spent once the message is confirmed sent — a failed delivery costs you nothing. Everyone can control which external channels they receive under their own Account page; essential notices such as receipts and invoices always get through.</p>\n    </section>\n\n    <!-- ================================================================= -->\n    <section id=\"rhythm\">\n      <div class=\"sec-label\">Practice</div>\n      <h2 class=\"sec-title\">Your operating rhythm</h2>\n      <p class=\"lede\">The difference between schools that get value from this system and schools that fight it is almost entirely habit. This is a workable one.</p>\n\n      <div class=\"cards\">\n        <div class=\"card\">\n          <h4>Each morning · 5 min</h4>\n          <ul>\n            <li>Clear <strong>Approvals</strong> — nothing should wait a day</li>\n            <li>Scan <strong>Notifications</strong></li>\n            <li>Check attendance was taken</li>\n          </ul>\n        </div>\n        <div class=\"card\">\n          <h4>Each week · 20 min</h4>\n          <ul>\n            <li><strong>Fees → Reports</strong> — collection and ageing</li>\n            <li>Any open <strong>disputes</strong> — these have deadlines</li>\n            <li><strong>Analytics</strong> — attendance trend by class</li>\n            <li>Cover arranged for next week's absences</li>\n          </ul>\n        </div>\n        <div class=\"card\">\n          <h4>Each term · 1 hr</h4>\n          <ul>\n            <li><strong>Recertification</strong> — who still needs access</li>\n            <li>Review the <strong>audit log</strong> for anything unfamiliar</li>\n            <li>Confirm results were published and cards issued</li>\n            <li>Check the subscription against real student numbers</li>\n          </ul>\n        </div>\n        <div class=\"card\">\n          <h4>Each year · half a day</h4>\n          <ul>\n            <li>Roll classes and the academic session forward</li>\n            <li>Archive leavers; add them to <strong>Alumni</strong></li>\n            <li>Review your plan against what you actually use</li>\n            <li>Confirm a restore from backup has been tested</li>\n          </ul>\n        </div>\n      </div>\n\n      <div class=\"note\">\n        <span class=\"note-tag\">The one habit that matters most</span>\n        <p>Clear your Approvals queue daily. Almost everything that stalls in this system — a payment not credited, a teacher's leave unconfirmed, results not reaching parents — is waiting on a decision, not on the software. Five minutes each morning prevents nearly all of it.</p>\n      </div>\n    </section>\n\n    <!-- ================================================================= -->\n    <section id=\"troubleshooting\">\n      <div class=\"sec-label\">Support</div>\n      <h2 class=\"sec-title\">When something goes wrong</h2>\n\n      <details>\n        <summary>A member of staff says they cannot see a page</summary>\n        <p>Check whether it is missing for you too. If it is missing for everyone, your plan does not include that module — <a href=\"#contact\">contact us</a> to enable it. If only they cannot see it, they lack the role: fix it under <strong>Admin → Roles</strong>. Have them sign out and back in afterwards, as permissions are read at login.</p>\n      </details>\n\n      <details>\n        <summary>Someone is locked out</summary>\n        <p>Three failed passwords locks an account permanently. An administrator reactivates it from the user's record. If it is <em>your</em> account and you have no second administrator, <a href=\"#contact\">message us on WhatsApp</a> — and appoint a second administrator once you are back in.</p>\n      </details>\n\n      <details>\n        <summary>A payment does not appear against an invoice</summary>\n        <p>Give it a few minutes; card payments confirm asynchronously. If it still has not landed, check whether it is held awaiting approval — payments of ₦50,000 and above wait for a second person. Failing that, a daily reconciliation sweep compares your ledger against the payment gateway and posts anything missing.</p>\n      </details>\n\n      <details>\n        <summary>A parent says they cannot see their child</summary>\n        <p>The guardian link is missing. Link them under <strong>Classes</strong>, on the child's record. This is the single most common data gap after a bulk import that did not include parent columns.</p>\n      </details>\n\n      <details>\n        <summary>I approved something by mistake</summary>\n        <p>Approvals are deliberately not reversible — that is what makes the record trustworthy. Correct it with a compensating action instead: for a payment, record a refund (which itself needs a second approver); for a role, remove it. Both the original decision and the correction remain visible in the audit log, which is the honest outcome.</p>\n      </details>\n\n      <details>\n        <summary>The system feels slow</summary>\n        <p>First establish whether it is slow for everyone or one person — a single slow user is almost always their network. If it is genuinely school-wide and sustained, <a href=\"#contact\">tell us</a>: capacity is adjustable, and slowness is a signal to act on rather than tolerate.</p>\n      </details>\n\n      <details>\n        <summary>I need to know who changed something</summary>\n        <p><strong>Admin → Audit</strong>, filtered by date, person or record. Every sensitive action is there, and the log cannot be altered by anyone.</p>\n      </details>\n    </section>\n\n    <!-- ================================================================= -->\n    <section id=\"reference\">\n      <div class=\"sec-label\">Reference</div>\n      <h2 class=\"sec-title\">Quick reference</h2>\n\n      <h3>Thresholds and limits</h3>\n      <div class=\"table-wrap\">\n        <table>\n          <thead><tr><th>Setting</th><th>Value</th></tr></thead>\n          <tbody>\n            <tr><td>Payment requiring a second approver</td><td class=\"num\">₦50,000 and above</td></tr>\n            <tr><td>Refunds requiring a second approver</td><td class=\"num\">All, any amount</td></tr>\n            <tr><td>Failed logins before lockout</td><td class=\"num\">3</td></tr>\n            <tr><td>Password expiry</td><td class=\"num\">30 days</td></tr>\n            <tr><td>Idle sign-out (60s warning first)</td><td class=\"num\">10 minutes</td></tr>\n            <tr><td>Set-password link validity</td><td class=\"num\">7 days</td></tr>\n            <tr><td>Password reset link validity</td><td class=\"num\">30 minutes</td></tr>\n            <tr><td>Renewal warning before expiry</td><td class=\"num\">14 days</td></tr>\n            <tr><td>School logo</td><td class=\"num\">Square, 128–2048px</td></tr>\n          </tbody>\n        </table>\n      </div>\n\n      <h3>Where things live</h3>\n      <div class=\"table-wrap\">\n        <table>\n          <thead><tr><th>To do this…</th><th>Go here</th></tr></thead>\n          <tbody>\n            <tr><td>Add staff, assign roles</td><td>Admin → Users / Roles</td></tr>\n            <tr><td>Import students</td><td>Admin → Bulk import</td></tr>\n            <tr><td>See who did what</td><td>Admin → Audit</td></tr>\n            <tr><td>Grant temporary access</td><td>Admin → Security</td></tr>\n            <tr><td>Review who holds what</td><td>Admin → Recertification</td></tr>\n            <tr><td>Handle a data request</td><td>Admin → Privacy</td></tr>\n            <tr><td>Upload your logo</td><td>Admin → Branding</td></tr>\n            <tr><td>Require staff 2FA</td><td>Admin → Roles</td></tr>\n            <tr><td>Approve anything</td><td>Approvals</td></tr>\n            <tr><td>Collection and ageing</td><td>Fees → Reports</td></tr>\n            <tr><td>Card disputes</td><td>Fees → Disputes</td></tr>\n            <tr><td>Your plan and renewal</td><td>Billing</td></tr>\n            <tr><td>Buy SMS credits</td><td>Billing</td></tr>\n            <tr><td>Cover an absent teacher</td><td>Timetable → Teacher cover</td></tr>\n            <tr><td>Your own 2FA and password</td><td>Account</td></tr>\n          </tbody>\n        </table>\n      </div>\n\n      <h3>Terms you will meet</h3>\n      <div class=\"table-wrap\">\n        <table>\n          <thead><tr><th>Term</th><th>Meaning</th></tr></thead>\n          <tbody>\n            <tr><td>Maker-checker</td><td>One person requests, a different person approves. Used wherever money or power moves.</td></tr>\n            <tr><td>Step-up</td><td>Being asked for your password again for a sensitive action, though already signed in.</td></tr>\n            <tr><td>Elevation</td><td>Temporary extra access, approved by someone else and automatically expiring.</td></tr>\n            <tr><td>Module</td><td>A product area your plan does or does not include.</td></tr>\n            <tr><td>Permission</td><td>A specific thing a role may do, such as recording a payment.</td></tr>\n            <tr><td>Scoping</td><td>Why a teacher sees only their classes and a parent only their children.</td></tr>\n            <tr><td>Recertification</td><td>Periodic review of who still needs the access they hold.</td></tr>\n            <tr><td>Settlement</td><td>Fees paid by card reaching your school's bank account.</td></tr>\n            <tr><td>Dunning</td><td>Reminders sent when a subscription payment is overdue.</td></tr>\n          </tbody>\n        </table>\n      </div>\n\n      <h3 id=\"contact\">Reaching us</h3>\n\n      <p>You will meet three names, so it is worth setting them out once:</p>\n      <ul>\n        <li><strong>MAESTRO-SMS</strong> is this product — the school management system your school subscribes to.</li>\n        <li><strong>MajorGBN Innovations Limited</strong> is the company behind it. Your subscription is paid to MajorGBN; the fees you collect from parents are not.</li>\n        <li><strong>majormaestro.com</strong> is the support desk, shared across every MajorGBN product.</li>\n      </ul>\n\n      <p>Guidance inside the app adapts to whoever is signed in — direct staff to <strong>Help</strong> before they ask you. For anything this manual does not cover:</p>\n\n      <div class=\"table-wrap\">\n        <table>\n          <thead><tr><th>Channel</th><th>Use it for</th></tr></thead>\n          <tbody>\n            <tr>\n              <td><a href=\"mailto:support@majormaestro.com\">support@majormaestro.com</a></td>\n              <td>Anything needing a record — billing queries, account recovery, data requests, formal correspondence.</td>\n            </tr>\n            <tr>\n              <td><a href=\"https://wa.me/2349039586647\">WhatsApp +234 903 958 6647</a></td>\n              <td>Urgent operational problems — a locked-out administrator, fees not settling, something blocking the school day.</td>\n            </tr>\n          </tbody>\n        </table>\n      </div>\n\n      <p>Because the desk covers every MajorGBN product, <strong>say MAESTRO-SMS in your first line</strong> — it routes you to the right team immediately. Then include your <strong>school name</strong>, the <strong>page you were on</strong>, and <strong>what you expected to happen</strong>. If it concerns a specific record — an invoice, a student, a payment — the reference from that page identifies it and saves a round of questions.</p>\n\n      <footer class=\"doc-foot\">\n        <p>MAESTRO-SMS is a product of MajorGBN Innovations Limited. This manual describes the system as configured for your school; the features available to you depend on your subscription plan.</p>\n      </footer>\n    </section>\n\n  </main>\n</div>\n\n<script>\n  // Mobile contents disclosure\n  (function () {\n    var btn = document.getElementById(\"tocToggle\");\n    var list = document.getElementById(\"tocList\");\n    if (!btn || !list) return;\n    function sync() {\n      var small = window.matchMedia(\"(max-width: 900px)\").matches;\n      if (small && btn.getAttribute(\"aria-expanded\") !== \"true\") list.hidden = true;\n      else list.hidden = false;\n    }\n    btn.addEventListener(\"click\", function () {\n      var open = btn.getAttribute(\"aria-expanded\") === \"true\";\n      btn.setAttribute(\"aria-expanded\", String(!open));\n      list.hidden = open;\n    });\n    list.addEventListener(\"click\", function (e) {\n      if (e.target.tagName === \"A\" && window.matchMedia(\"(max-width: 900px)\").matches) {\n        btn.setAttribute(\"aria-expanded\", \"false\");\n        list.hidden = true;\n      }\n    });\n    window.addEventListener(\"resize\", sync);\n    sync();\n  })();\n\n  // Highlight the section currently in view\n  (function () {\n    var links = Array.prototype.slice.call(document.querySelectorAll(\"#tocList a\"));\n    var byId = {};\n    links.forEach(function (a) { byId[a.getAttribute(\"href\").slice(1)] = a; });\n    var sections = Array.prototype.slice.call(document.querySelectorAll(\"main section\"));\n    if (!(\"IntersectionObserver\" in window) || !sections.length) return;\n\n    var visible = new Set();\n    var obs = new IntersectionObserver(function (entries) {\n      entries.forEach(function (en) {\n        if (en.isIntersecting) visible.add(en.target.id);\n        else visible.delete(en.target.id);\n      });\n      var top = sections.filter(function (s) { return visible.has(s.id); })[0];\n      if (!top) return;\n      links.forEach(function (a) { a.classList.remove(\"active\"); });\n      if (byId[top.id]) byId[top.id].classList.add(\"active\");\n    }, { rootMargin: \"-10% 0px -70% 0px\", threshold: 0 });\n\n    sections.forEach(function (s) { obs.observe(s); });\n  })();\n</script>\n";
